'use client'
import { getLinkComponent, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import styles from './dock.module.css'

export interface DockItem {
  label: string
  icon: React.ReactNode
  onClick?: () => void
  href?: string
}

export interface DockProps {
  items: DockItem[]
  activeIndex?: number
  className?: string
  /** Accessible label for the nav landmark */
  ariaLabel?: string
}

export function Dock({ items, activeIndex, className, ariaLabel }: DockProps) {
  useSignals()
  const resolvedAriaLabel = ariaLabel ?? t(builtin.dock.nav)
  return (
    <nav
      aria-label={resolvedAriaLabel}
      className={[styles.dock, className].filter(Boolean).join(' ')}
    >
      {items.map((item, i) => {
        const isActive = i === activeIndex
        const Tag = item.href ? getLinkComponent() : 'button'
        return (
          <Tag
            key={i}
            className={styles.item}
            data-active={isActive || undefined}
            aria-current={isActive ? 'page' : undefined}
            {...(item.href ? { href: item.href } : {})}
            type={item.href ? undefined : 'button'}
            onClick={item.onClick}
          >
            <span className={styles.icon} aria-hidden="true">
              {item.icon}
            </span>
            <span className={styles.label}>{item.label}</span>
          </Tag>
        )
      })}
    </nav>
  )
}

@layer cascivo.component {
  .dock {
    position: fixed;
    inset-block-end: 0;
    inset-inline: 0;
    display: flex;
    align-items: stretch;
    background-color: var(--cascivo-color-surface);
    border-block-start: 1px solid var(--cascivo-border-subtle);
    padding-block-end: env(safe-area-inset-bottom, 0);
    z-index: var(--cascivo-z-dock, 40);
  }

  @media (min-width: 64rem) {
    .dock {
      display: none;
    }
  }

  .item {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    flex: 1;
    gap: 0.25rem;
    padding-block: 0.5rem;
    padding-inline: 0.25rem;
    min-block-size: var(--cascivo-target-min-coarse, 2.75rem);
    background: none;
    border: none;
    cursor: pointer;
    color: var(--cascivo-color-text-muted);
    text-decoration: none;
    transition: color 100ms var(--cascivo-ease-out);
  }

  .item[data-active] {
    color: var(--cascivo-color-accent);
  }

  .item:focus-visible {
    outline: var(--cascivo-ring-width) solid var(--cascivo-ring-color);
    outline-offset: -2px;
  }

  .icon {
    display: flex;
    align-items: center;
    font-size: 1.25rem;
    line-height: 1;
  }

  .label {
    font-size: 0.6875rem;
    line-height: 1;
  }

  .item[data-active] .label {
    font-weight: 600;
  }
}
